import{_ as s,I as a,o as n,c as l,j as t,J as o,ak as c}from"./chunks/framework.DJ-92fJv.js";const y=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"Wisp","text":"All-in-One Networking for Roblox","tagline":"Buffer-Based. Safety. Schemas. Fast.","image":{"light":"\\\\assets/Wisp-Logo.png","dark":"\\\\assets/Wisp-Logo.png","alt":"Wisp Logo"},"actions":[{"theme":"brand","text":"Getting started","link":"/tutorials"},{"theme":"alt","text":"API Reference","link":"/api"},{"theme":"alt","text":"Download","link":"https://github.com/maneetoo/wisp/releases"}]}},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),p={name:"index.md"};function d(h,e,u,m,b,f){const r=a("ScrollIndicator"),i=a("NextSteps");return n(),l("div",null,[e[0]||(e[0]=t("div",{class:"warning custom-block"},[t("p",{class:"custom-block-title"},"Pre-Beta Release"),t("p",null,"Wisp is in active development. Although the module passes all checks, some edge-cases may cause errors, data loss, and so on. For large projects, it is better wait for a stable version of Wisp or use similar alternatives. We would appreciate your help in finding vulnerabilities in the module by opening Issues and Pull Requests! Thank you so much!")],-1)),o(r),o(i,{links:[{title:"Getting Started",description:"Installation, quick start, and your first UI component",href:"/tutorials"},{title:"API Reference",description:"Complete documentation for all reactive primitives",href:"/api-reference"},{title:"Benchmarks",description:"See benchmarks compared to other libraries",href:"/benchmarks"}]}),e[1]||(e[1]=c('<h2 id="about-wisp" tabindex="-1">About Wisp <a class="header-anchor" href="#about-wisp" aria-label="Permalink to “About Wisp”">​</a></h2><p>Wisp is a binary networking framework for Roblox built on the buffer library. It handles serialization, compression, batching, delta encoding, and schema validation in a single package designed to work together from the start.</p><p>Every component was built with awareness of the others. The serializer knows what the compressor needs. The batcher knows which queue to use. The schema validator knows how to call the migration system when old data arrives.</p><p>Wisp supports 51 Roblox types natively, validates every argument at runtime, and includes versioned schemas with automatic migration so your protocol can evolve without breaking old clients.</p><h2 id="why-wisp" tabindex="-1">Why Wisp? <a class="header-anchor" href="#why-wisp" aria-label="Permalink to “Why Wisp?”">​</a></h2><p>Building networking in Roblox the traditional way means choosing between convenience and control. You either use a simple wrapper that hides the complexity but adds overhead you can&#39;t remove, or you write everything from scratch using raw <a href="https://create.roblox.com/docs/scripting/events/remote" target="_blank" rel="noreferrer">RemoteEvents</a> and spend weeks reinventing compression, delta encoding, and batch queues. Neither approach scales well as your game grows.</p><p>Wisp gives you both. It handles every aspect of networking — <a href="https://create.roblox.com/docs/reference/engine/libraries/buffer" target="_blank" rel="noreferrer">serialization</a>, compression, batching, delta encoding, rate limiting, schema validation — while keeping you in full control of how each remote behaves. Need positions sent as fast as possible without guarantees? Make it unreliable with <a href="https://create.roblox.com/docs/scripting/events/unreliable-remote" target="_blank" rel="noreferrer">UnreliableRemoteEvents</a> and priority queuing. Need purchases to never be lost? Switch it to reliable with automatic retry. Every decision is a one-line configuration change, not a rewrite.</p><p>Wisp operates at the binary level, not the string level. Where other libraries send JSON objects with repeated field names and unnecessary markup, Wisp packs your data into the smallest possible <a href="https://create.roblox.com/docs/reference/engine/libraries/buffer" target="_blank" rel="noreferrer">buffer</a> using a custom 51-type serializer. A <a href="https://create.roblox.com/docs/reference/engine/datatypes/Vector3" target="_blank" rel="noreferrer">Vector3</a> becomes 13 bytes instead of 40. A table of ten player stats becomes a compact binary stream instead of hundreds of characters. Multiply that by thousands of packets per minute and the difference is measured in megabytes of bandwidth and milliseconds of latency.</p><p>The framework is also designed for games that evolve. Wisp includes schema versioning and migration functions, so you can change your data format without breaking old clients. Delta encoding with cache synchronization means you only send what changed, not the entire state, with automatic detection and recovery when client and server fall out of sync.</p><p>Wisp validates every argument to every public method before it reaches your game logic. A typo in a remote name or a missing player argument is caught immediately with a clear error message, not silently ignored until it causes a cascade of bugs hours later. Combined with extensive unit tests covering every module, you can refactor with confidence.</p><p>Wisp is written in <a href="https://luau.org/" target="_blank" rel="noreferrer">Luau</a> with <code>--!strict</code> mode and <code>--!native</code> optimizations enabled throughout. The entire framework is built on the <a href="https://create.roblox.com/docs/reference/engine/libraries/buffer" target="_blank" rel="noreferrer">buffer</a> library introduced by Roblox for maximum performance, avoiding the overhead of string-based serialization entirely.</p><p>When you choose Wisp, you&#39;re not just picking a networking library. You&#39;re choosing a foundation that handles the hard parts of multiplayer — bandwidth optimization, data integrity, protocol evolution — so you can focus on building your game.</p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to “Key Features”">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Minimal Packet Size</p><p>Binary serialization with a custom 51-type encoder built on Roblox&#39;s <a href="https://create.roblox.com/docs/reference/engine/libraries/buffer" target="_blank" rel="noreferrer">buffer</a> library. A Vector3 is 13 bytes instead of 40. A CFrame is 29 bytes instead of 150. Every byte counts.</p></div><div class="tip custom-block"><p class="custom-block-title">Smart Compression</p><p>Three compression algorithms — LZ4HC for speed, Deflate for text, Zstd for large payloads — plus an XOR pre-processor that breaks repetitive patterns before compression, improving ratios by up to 15%.</p></div><div class="tip custom-block"><p class="custom-block-title">Delta Encoding</p><p>Send only what changed between packets. Wisp tracks state per-player and transmits just the differences, with automatic cache synchronization and recovery when client and server fall out of sync.</p></div><div class="tip custom-block"><p class="custom-block-title">Dual-Channel Batching</p><p>Separate reliable and unreliable batch queues with priority ordering. High-frequency position updates go through UnreliableRemoteEvents for minimum latency. Critical purchases go through guaranteed delivery. All batched per-frame to minimize RemoteEvent calls.</p></div><div class="tip custom-block"><p class="custom-block-title">Schema Validation &amp; Migration</p><p>Define your data structure once with typed schemas. Wisp validates every packet before it reaches your game logic. When your protocol evolves, migration functions upgrade old data automatically — no broken clients, no manual version checks.</p></div><div class="tip custom-block"><p class="custom-block-title">Zero-Configuration Types</p><p>51 Roblox types work out of the box — Vectors, CFrames, Colors, Enums, Instances, and more. No manual serialization, no type registration, no boilerplate.</p></div>',19))])}const v=s(p,[["render",d]]);export{y as __pageData,v as default};
